import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-admin-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './admin-dashboard.component.html',
  styleUrls: ['./admin-dashboard.component.css']
})
export class AdminDashboardComponent implements OnInit {
  stats: any = { totalUsers: 0, pendingAudits: 0, totalNotaries: 0 };
  pendingRequests: any[] = [];
  notaries: any[] = [];
  activeTab: 'AUDITS' | 'PROJECTS' | 'USERS' = 'AUDITS';
  isLoading: boolean = true;

  constructor(private http: HttpClient) {}

  ngOnInit() {
    this.loadAdminData();
  }

  loadAdminData() {
    this.isLoading = true;
    // In prototype, mock admin data if API fails
    setTimeout(() => {
      this.stats = { totalUsers: 1250, pendingAudits: 14, totalNotaries: 45 };
      this.pendingRequests = [
        { id: 'req-101', titleNumber: 'Vol 45 Fol 12', requester: 'Paul Biya', date: '2024-03-28' },
        { id: 'req-102', titleNumber: 'Vol 89 Fol 04', requester: 'Samuel Etoo', date: '2024-03-30' }
      ];
      this.notaries = [
        { id: 'not-1', fullName: 'Me. Akere Muna' },
        { id: 'not-2', fullName: 'Me. Alice Nkom' }
      ];
      this.isLoading = false;
    }, 1000);
  }

  assignNotary(requestId: string, notaryId: string) {
    console.log(`Assigning request ${requestId} to notary ${notaryId}`);
    // Simulate API call
    this.pendingRequests = this.pendingRequests.filter(r => r.id !== requestId);
    alert('Notaire assigné avec succès !');
  }
}
<div class="admin-dashboard">
  <div class="header-section" style="margin-bottom: 2rem;">
    <h2>maTerre Command Center (ADMIN)</h2>
    <p>Gestion globale des flux d'arbitrage et des investissements.</p>
  </div>

  <!-- Stats Grid -->
  <div class="stats-grid" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1.5rem; margin-bottom: 3rem;">
    <div class="card" style="background: #f5f5f5;">
      <p style="margin: 0; font-size: 0.8rem; color: #888;">UTILISATEURS</p>
      <p style="margin: 5px 0 0 0; font-size: 1.5rem; font-weight: bold;">{{ stats.totalUsers }}</p>
    </div>
    <div class="card" style="background: #fff8e1; border-left: 5px solid var(--mt-gold);">
      <p style="margin: 0; font-size: 0.8rem; color: #c5a000;">AUDITS EN ATTENTE</p>
      <p style="margin: 5px 0 0 0; font-size: 1.5rem; font-weight: bold; color: var(--mt-red);">{{ stats.pendingAudits }}</p>
    </div>
    <div class="card" style="background: #e8f5e9; border-left: 5px solid var(--mt-green);">
      <p style="margin: 0; font-size: 0.8rem; color: var(--mt-green);">NOTAIRES PARTENAIRES</p>
      <p style="margin: 5px 0 0 0; font-size: 1.5rem; font-weight: bold;">{{ stats.totalNotaries }}</p>
    </div>
  </div>

  <!-- Tabs -->
  <div style="display: flex; gap: 20px; border-bottom: 2px solid #eee; margin-bottom: 2rem;">
    <button (click)="activeTab = 'AUDITS'" [style.border-bottom]="activeTab === 'AUDITS' ? '3px solid var(--mt-green)' : 'none'" style="background: none; border: none; padding: 10px 20px; cursor: pointer; font-weight: bold;">Audits & Notaires</button>
    <button (click)="activeTab = 'PROJECTS'" [style.border-bottom]="activeTab === 'PROJECTS' ? '3px solid var(--mt-green)' : 'none'" style="background: none; border: none; padding: 10px 20px; cursor: pointer; font-weight: bold;">Projets de Financement</button>
    <button (click)="activeTab = 'USERS'" [style.border-bottom]="activeTab === 'USERS' ? '3px solid var(--mt-green)' : 'none'" style="background: none; border: none; padding: 10px 20px; cursor: pointer; font-weight: bold;">Utilisateurs</button>
  </div>

  <!-- Tab Content: Audits -->
  <div *ngIf="activeTab === 'AUDITS'">
    <h3>Pipeline d'Arbitrage Express</h3>
    <table style="width: 100%; border-collapse: collapse; margin-top: 1rem;">
      <thead>
        <tr style="text-align: left; background: #eee;">
          <th style="padding: 12px;">Titre</th>
          <th style="padding: 12px;">Demandeur</th>
          <th style="padding: 12px;">Date</th>
          <th style="padding: 12px;">Action (Assigner Notaire)</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let req of pendingRequests" style="border-bottom: 1px solid #eee;">
          <td style="padding: 12px; font-weight: bold;">{{ req.titleNumber }}</td>
          <td style="padding: 12px;">{{ req.requester }}</td>
          <td style="padding: 12px;">{{ req.date }}</td>
          <td style="padding: 12px;">
            <select #notarySelect style="padding: 8px; border-radius: 4px;">
              <option value="">-- Choisir un Notaire --</option>
              <option *ngFor="let n of notaries" [value]="not-1">{{ n.fullName }}</option>
            </select>
            <button (click)="assignNotary(req.id, notarySelect.value)" class="btn-primary" style="padding: 5px 10px; margin-left: 10px; font-size: 0.8rem;">Assigner</button>
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div *ngIf="activeTab === 'PROJECTS'" style="padding: 2rem; text-align: center;">
    <p>Gestion des pools de co-investissement en cours de déploiement...</p>
  </div>

  <div *ngIf="activeTab === 'USERS'" style="padding: 2rem; text-align: center;">
    <p>Annuaire global des utilisateurs et abonnements Elite...</p>
  </div>
</div>
